function solve(n, edges, source, target, k) {
    if (source === target) {
        return 0;
    }

    // 1. Graph Construction
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }

    /**
     * Checks if a path exists from source to target using at most k heavy edges, 
     * given the threshold T.
     * Uses 0-1 BFS since edge weights (heavy count) are 0 or 1.
     * @param {number} T The threshold.
     * @returns {boolean} True if a valid path exists, false otherwise.
     */
    const canReach = (T) => {
        // C[u] stores the minimum number of heavy edges required to reach node u.
        // Initialize to k + 1 (infinity relative to k).
        const C = Array(n).fill(k + 1);
        C[source] = 0;

        // Deque implementation using an array:
        // Elements pushed to front (unshift) have cost 0.
        // Elements pushed to back (push) have cost 1.
        const deque = [source];

        let head = 0;
        while (head < deque.length) {
            const u = deque[head++];
            const current_heavy_count = C[u];

            if (u === target) {
                // Optimization: If we reached target, since BFS guarantees minimum cost,
                // and we already ensured current_heavy_count <= k, we can return true immediately.
                return true;
            }

            for (const [v, w] of adj[u]) {
                const is_heavy = w > T ? 1 : 0;
                const new_heavy_count = current_heavy_count + is_heavy;

                if (new_heavy_count <= k && new_heavy_count < C[v]) {
                    C[v] = new_heavy_count;

                    if (is_heavy === 0) {
                        // Cost 0 edge: push to front (conceptually)
                        // In array simulation, we insert at the beginning and adjust head pointer logic 
                        // or use a true deque structure. Given JS constraints, simulating deque efficiently is hard.
                        // For 0-1 BFS correctness, we need 0-cost nodes processed before 1-cost nodes.
                        // We will use unshift/push and rely on the array structure, which maintains order correctly 
                        // if we treat the front of the array as the front of the queue.

                        // Resetting simulation for simplicity and correctness:
                        // Since we are re-initializing the queue logic entirely if we used head++, 
                        // let's use standard queue structure logic for simplicity, treating deque as a list and popping/pushing.
                        // Note: This might degrade to O(N^2) if unshift is slow, but N=1000 is usually okay.

                        // Reverting to standard array usage simulating queue/deque structure for simplicity in implementation:
                        deque.unshift(v);
                    } else {
                        // Cost 1 edge: push to back
                        deque.push(v);
                    }
                }
            }
        }

        return C[target] <= k;
    };

    // Re-implementing 0-1 BFS structure using proper queue operations (less efficient array operations, but clearer)
    const canReachOptimized = (T) => {
        const C = Array(n).fill(k + 1);
        C[source] = 0;

        // Deque simulation: store nodes. Cost 0 nodes go to the front, Cost 1 to the back.
        const deque = [];
        deque.push(source);

        while (deque.length > 0) {
            const u = deque.shift(); // Standard pop front

            if (u === target) return true;

            const current_heavy_count = C[u];

            for (const [v, w] of adj[u]) {
                const is_heavy = w > T ? 1 : 0;
                const new_heavy_count = current_heavy_count + is_heavy;

                if (new_heavy_count <= k && new_heavy_count < C[v]) {
                    C[v] = new_heavy_count;

                    // 0-1 BFS logic: if cost is 0, prepend. If cost is 1, append.
                    if (is_heavy === 0) {
                        deque.unshift(v); // Prepend for 0-cost transition
                    } else {
                        deque.push(v); // Append for 1-cost transition
                    }
                }
            }
        }
        return C[target] <= k;
    };


    // 2. Binary Search on Threshold T
    // Search range: [0, 10^9 + 1]. Max weight is 10^9.
    let low = 0;
    let high = 10**9 + 1; 
    let min_threshold = -1;

    while (low <= high) {
        // Using Math.floor for safe integer division
        const mid = Math.floor((low + high) / 2);

        if (canReachOptimized(mid)) {
            // Path found with threshold mid. This might be the minimum. Try smaller.
            min_threshold = mid;
            high = mid - 1;
        } else {
            // Path not found. Need a larger threshold to turn more heavy edges into light ones.
            low = mid + 1;
        }
    }

    return min_threshold;
}

